    @Override public CssToken peek() {
      return idx < list.size() ? list.get(idx) : last;
    }
    @Override public int index() { return idx - 1; }
    @Override public List<CssToken> list() { return list; }
    @Override public com.google.common.base.Predicate<CssToken> filter() { return null; }
  }

  @Test
  @DisplayName("parse(): breaks loop on PrematureEOFException thrown by handleAtRule and still calls endDocument")
  public void test_TC15() throws IOException {
